import {TriStateCheckbox} from "primereact/tristatecheckbox";
import type {EditorEl} from "../Editor";

const TriStateEditor: EditorEl = (options) => {
  return (
    <TriStateCheckbox
      value={options.value}
      onChange={(e) => options.editorCallback && options.editorCallback(e.value)}
    />
  );
};

export default TriStateEditor;
